<script>
document.addEventListener('DOMContentLoaded', function() {
    var hamburger = document.querySelector('.mobile-layout-only .block-header__m-menu-icon');
    if (!hamburger) hamburger = document.querySelector('.mobile-layout-only .burger');
    var nav = document.querySelector('.mobile-layout-only .block-header-layout-mobile__dropdown');
    
    if (hamburger && nav) {
        hamburger.addEventListener('click', function() {
            var isOpen = nav.classList.contains('block-header-layout-mobile__dropdown--open');
            if (isOpen) {
                nav.classList.remove('block-header-layout-mobile__dropdown--open');
                hamburger.classList.remove('burger--open');
                document.body.style.overflow = '';
            } else {
                nav.classList.add('block-header-layout-mobile__dropdown--open');
                hamburger.classList.add('burger--open');
                document.body.style.overflow = 'hidden';
            }
        });
    }
});
</script>

